def identity_agreement(text: str, work: Work) -> dict:
    """Do these bytes belong to the Work the row claims? THE CHECK THAT CATCHES A DIFFERENT PAPER.

    Not one component asked this. A title matcher matched "Rise of the Machines" and handed us a
    mathematics preprint; every downstream check then verified, correctly and irrelevantly, that the
    span was verbatim IN THE MATHEMATICS PREPRINT.
    """
    head = text[:20000]
    authors = [a for a in (work.authors or []) if len(a) > 2]
    named = [a for a in authors if re.search(r'\b' + re.escape(a) + r'\b', head, re.I)]
    twords = {w for w in re.findall(r'[a-z]{5,}', (work.title or '').lower())}
    tfound = {w for w in twords if w in head.lower()}

    # CONTRADICTED needs BOTH signals to fail: a legitimately-extracted PDF can lose its author
    # block to the header stripper while keeping every word of its title. One weak signal proves
    # nothing, and a false CONTRADICTED would destroy good evidence.
    if authors and not named and twords and len(tfound) < 0.5 * len(twords):
        verdict = 'CONTRADICTED'
    elif named or (twords and len(tfound) >= 0.8 * len(twords)):
        verdict = 'CONFIRMED'
    else:
        verdict = 'UNRESOLVED'
    return dict(verdict=verdict,
                authors_named=len(named), authors_claimed=len(authors),
                title_words_found=len(tfound), title_words=len(twords))

